// Replace 'devops@yourcompany.com' with an email address you have actually verified with SendGrid.
const DEFAULT_SENDER_EMAIL = 'devops@yourcompany.com';

/**
 * Sends an email notification using the SendGrid API.
 * This function is designed for simple, internal use within a trusted DevOps team.
 *
 * @param {string} to - The recipient's email address.
 * @param {string} subject - The subject line of the email.
 * @param {string} text - The plain text content of the email.
 * @param {string} [html] - Optional HTML content of the email. If not provided, 'text' will be used for HTML part.
 * @param {string} [from=DEFAULT_SENDER_EMAIL] - Optional sender email address. Defaults to DEFAULT_SENDER_EMAIL.
 *                                                Must be a verified sender in SendGrid.
 * @returns {Promise<void>} A Promise that resolves when the email is sent, or rejects on error.
 */
async function sendEmailNotification(to, subject, text, html, from = DEFAULT_SENDER_EMAIL) {
  if (!to || !subject || !text) {
    throw new Error('Recipient email, subject, and text content are required to send an email.');
  }

  // Provide a warning if the default placeholder 'from' address is still in use.
  if (from === 'devops@yourcompany.com') {
      console.warn('WARNING: The default sender email "devops@yourcompany.com" has not been updated. Please ensure this is a verified sender in your SendGrid account or replace it with one. Otherwise, emails may fail to send.');
  }

  const msg = {
    to: to,
    from: from,
    subject: subject,
    text: text,
    html: html || text, // Use HTML content if provided, otherwise use plain text for both.
  };

  try {
    // SendGrid's send method returns an array containing the response.
    const [response] = await sgMail.send(msg);

    // Check for successful status codes (2xx range).
    if (response.statusCode >= 200 && response.statusCode < 300) {
      console.log(`Email sent successfully to ${to}. Status: ${response.statusCode}`);
    } else {
      // Log and throw an error for non-2xx status codes.
      const errorDetails = response.body ? JSON.stringify(response.body) : 'No response body';
      console.error(`Failed to send email to ${to}. Status: ${response.statusCode}. Details: ${errorDetails}`);
      throw new Error(`SendGrid API error: Status ${response.statusCode}`);
    }
  } catch (error) {
    console.error(`Error sending email to ${to}:`, error);
    if (error.response && error.response.body) {
      // Log specific SendGrid API error details if available.
      console.error('SendGrid API error response body:', error.response.body);
    }
    throw error; // Re-throw the error to allow the caller to handle it.
  }
}

